INSERT INTO `questions` VALUES (1,1,'Aponte a alternativa grafada corretamente.','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','easy',2.50,0,0,75.00,NULL,NULL,1,'2025-08-11 17:53:25.891663','2025-08-11 17:53:25.891663',NULL,NULL,NULL,NULL),(2,1,'Aponte a alternativa em que está correta a separação das sílabas','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','medium',3.00,0,0,65.00,NULL,NULL,1,'2025-08-11 17:53:26.508501','2025-08-11 17:53:26.508501',NULL,NULL,NULL,NULL),(3,1,'Na oração \"Os ovos e os filhotes ficam sujeitos à chuva, às cobras, às formigas, às ventanias\", você percebe expressões craseadas. Aponte a alternativa em que está correto o uso da crase.','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','medium',3.20,0,0,58.00,NULL,NULL,1,'2025-08-11 17:53:27.110004','2025-08-11 17:53:27.110004',NULL,NULL,NULL,NULL),(4,1,'Assinale a alternativa que contenha, respectivamente: um pronome pessoal do caso reto funcionando como sujeito e um pronome pessoal do caso oblíquo funcionando com objeto direto','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','hard',3.80,0,0,45.00,NULL,NULL,1,'2025-08-11 17:53:27.699648','2025-08-11 17:53:27.699648',NULL,NULL,NULL,NULL),(5,1,'Aponte a alternativa em que mal e mau estão corretamente empregados','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','medium',3.00,0,0,62.00,NULL,NULL,1,'2025-08-11 17:53:28.337534','2025-08-11 17:53:28.337534',NULL,NULL,NULL,NULL),(6,1,'Assinale a frase em que está correta a correlação verbal.','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','medium',3.30,0,0,58.00,NULL,NULL,1,'2025-08-11 17:53:28.924693','2025-08-11 17:53:28.924693',NULL,NULL,NULL,NULL),(7,1,'Assinale a frase que não está na voz passiva.','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','hard',3.50,0,0,48.00,NULL,NULL,1,'2025-08-11 17:53:29.520131','2025-08-11 17:53:29.520131',NULL,NULL,NULL,NULL),(8,1,'Assinale a frase correta','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','medium',3.20,0,0,55.00,NULL,NULL,1,'2025-08-11 17:53:30.120345','2025-08-11 17:53:30.120345',NULL,NULL,NULL,NULL),(9,1,'Transpondo par a voz ativa a frase \"As frutas estavam sendo condicionas em caixas\" obtém-se a forma verbal:','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','hard',3.70,0,0,42.00,NULL,NULL,1,'2025-08-11 17:53:30.710655','2025-08-11 17:53:30.710655',NULL,NULL,NULL,NULL),(10,1,'Como todos ............... reunidos, ....-se a explicar o problema.','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','hard',3.80,0,0,38.00,NULL,NULL,1,'2025-08-11 17:53:31.306583','2025-08-11 17:53:31.306583',NULL,NULL,NULL,NULL),(11,2,'The sooner a man begins to work __________.','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','medium',2.80,0,0,68.00,NULL,NULL,1,'2025-08-11 17:53:31.898624','2025-08-11 17:53:31.898624',NULL,NULL,NULL,NULL),(12,2,'Fill in the blank of the following sentence correctly: The hole in front of his garage is becoming __________.','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','easy',2.30,0,0,72.00,NULL,NULL,1,'2025-08-11 17:53:32.502581','2025-08-11 17:53:32.502581',NULL,NULL,NULL,NULL),(13,2,'A lion is __________ than a dog.','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','easy',2.00,0,0,78.00,NULL,NULL,1,'2025-08-11 17:53:33.091584','2025-08-11 17:53:33.091584',NULL,NULL,NULL,NULL),(14,2,'Assinale a alternativa que preenche corretamente a lacuna da frase adiante: This hill is __________ than I thought it was.','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','medium',2.70,0,0,65.00,NULL,NULL,1,'2025-08-11 17:53:33.680259','2025-08-11 17:53:33.680259',NULL,NULL,NULL,NULL),(15,2,'Indicate the alternative that best completes the following sentence: His salary as a pilot is much higher __________.','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','medium',3.00,0,0,58.00,NULL,NULL,1,'2025-08-11 17:53:34.290644','2025-08-11 17:53:34.290644',NULL,NULL,NULL,NULL),(16,3,'O método da bisseção é um algoritmo usado para encontrar aproximações das raízes de uma equação. Começa-se com um intervalo [a,b], que contém uma raiz, e, em cada passo do algoritmo, reduz-se o intervalo pela metade, usando-se um teorema para determinar se a raiz está à esquerda ou à direita do ponto médio do intervalo anterior. Ou seja, após o passo 1, obtém-se um intervalo de comprimento b-a/2; após o passo 2, obtém-se um intervalo de comprimento b-a/4; e após o passo n, obtém-se um intervalo de comprimento b-a/2n. Esse processo continua até que o intervalo obtido tenha comprimento menor que o erro máximo desejado para a aproximação. Para aplicar esse método no intervalo [1,5], quantos passos serão necessários para obter-se um intervalo de comprimento menor que 10-3?','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','hard',4.20,0,0,35.00,NULL,NULL,1,'2025-08-11 17:53:34.879433','2025-08-11 17:53:34.879433',NULL,NULL,NULL,NULL),(17,3,'Para que seja possível administrar as vendas de uma empresa, é necessário estimar a demanda do mercado. Considere que uma cidade tenha 300.000 habitantes que consomem dois sabonetes por mês e que a participação da empresa X no mercado de sabonetes é de 30%. A demanda mensal por sabonetes da empresa X é de','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','medium',2.80,0,0,72.00,NULL,NULL,1,'2025-08-11 17:53:35.470227','2025-08-11 17:53:35.470227',NULL,NULL,NULL,NULL),(18,3,'Em uma progressão aritmética de 5 termos e primeiro termo 5, a soma dos quadrados dos três primeiros termos é igual à soma dos quadrados dos dois últimos termos. O maior valor possível para o último termo dessa progressão aritmética é','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','hard',4.00,0,0,32.00,NULL,NULL,1,'2025-08-11 17:53:36.067726','2025-08-11 17:53:36.067726',NULL,NULL,NULL,NULL),(19,3,'A probabilidade de sucesso em uma prova de campo é a nona parte da probabilidade de fracasso. Provas sucessivas e independentes são realizadas até que o sucesso ocorra pela primeira vez. Nessas circunstâncias, o número esperado de fracassos que deverão ocorrer até que se verifique o primeiro sucesso é igual a','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','hard',4.10,0,0,28.00,NULL,NULL,1,'2025-08-11 17:53:36.655626','2025-08-11 17:53:36.655626',NULL,NULL,NULL,NULL),(20,3,'O dono de uma loja deu um desconto de 20% sobre o preço de venda (preço original) de um de seus produtos e, ainda assim, obteve um lucro de 4% sobre o preço de custo desse produto. Se vendesse pelo preço original, qual seria o lucro obtido sobre o preço de custo?','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','medium',3.50,0,0,52.00,NULL,NULL,1,'2025-08-11 17:53:37.246658','2025-08-11 17:53:37.246658',NULL,NULL,NULL,NULL),(21,4,'Um dos objetivos almejados pelo Banco Central do Brasil, ao criar o Pix, é','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','medium',2.80,0,0,65.00,NULL,NULL,1,'2025-08-11 17:53:37.829061','2025-08-11 17:53:37.829061',NULL,NULL,NULL,NULL),(22,4,'Um token físico, no contexto de transações bancárias, é um dispositivo eletrônico que possui um botão de ativação e um pequeno visor. O token permite gerar senhas aleatórias, temporárias e numéricas (por exemplo, de seis dígitos). Essa senha é utilizada para dar mais segurança às transações bancárias realizadas via internet. No passado, os bancos comerciais disponibilizavam esses pequenos dispositivos aos seus clientes, de modo que pudessem ser afixados a um chaveiro. Mais recentemente, nos últimos 10 anos, esses dispositivos foram sendo gradativamente substituídos para a grande maioria dos clientes, por um','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','easy',2.20,0,0,75.00,NULL,NULL,1,'2025-08-11 17:53:38.422638','2025-08-11 17:53:38.422638',NULL,NULL,NULL,NULL),(23,4,'Um meio de troca é aquilo que os compradores oferecem aos vendedores quando aqueles adquirem bens e serviços. Quando um consumidor, por exemplo, compra um perfume numa loja localizada numa economia onde o nível inflacionário é baixo e controlado, o vendedor entrega o produto para o cliente em troca de','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','easy',2.00,0,0,78.00,NULL,NULL,1,'2025-08-11 17:53:39.017554','2025-08-11 17:53:39.017554',NULL,NULL,NULL,NULL),(24,4,'As startups têm transformado os negócios. Um dos motivos para isso é que elas','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','medium',2.50,0,0,68.00,NULL,NULL,1,'2025-08-11 17:53:39.611259','2025-08-11 17:53:39.611259',NULL,NULL,NULL,NULL),(25,4,'Uma pessoa estava querendo fazer um empréstimo e descobriu que algumas instituições que praticam o shadow banking (\"sistema bancário sombra\") geralmente servem como intermediários entre credores e tomadores de empréstimos, fornecendo crédito e capital para investidores e corporações. Ao fazer uso dessas instituições para fazer um empréstimo, a pessoa incorre em riscos?','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','hard',3.50,0,0,45.00,NULL,NULL,1,'2025-08-11 17:53:40.206906','2025-08-11 17:53:40.206906',NULL,NULL,NULL,NULL),(26,5,'Qual é a taxa de juros simples utilizada por uma aplicação para tornar um capital inicial de R$1.000,00 em um montante de R$1.240,00, em um período de um ano?','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','easy',2.50,0,0,72.00,NULL,NULL,1,'2025-08-11 17:53:40.799581','2025-08-11 17:53:40.799581',NULL,NULL,NULL,NULL),(27,5,'Um banco possui, atualmente, um modelo de financiamento em regime de juros compostos, em que as parcelas são pagas, mensalmente, a uma taxa de juros de 2% ao mês. Para um certo perfil de clientes, o banco pretende possibilitar o pagamento da dívida a cada três meses, a uma taxa de juros trimestral equivalente à praticada no modelo atual. A melhor aproximação para o valor da taxa de juros trimestral desse novo modelo de financiamento é:','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','medium',3.20,0,0,58.00,NULL,NULL,1,'2025-08-11 17:53:41.388564','2025-08-11 17:53:41.388564',NULL,NULL,NULL,NULL),(28,5,'Uma determinada empresa vem adotando uma política de reajustes de preços, de modo que o preço de seu principal produto sofreu um reajuste de 10% em Set/2017. Em outubro do mesmo ano, o produto sofreu novo reajuste, agora de 5% sobre o valor do mês anterior e, um mês depois, um terceiro reajuste de 6% foi aplicado sobre o preço de outubro, de modo que os três reajustes foram sucessivos. O valor mais próximo da variação percentual acumulada nesse período, considerando exatamente os três reajustes apresentados, é','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','medium',3.40,0,0,55.00,NULL,NULL,1,'2025-08-11 17:53:41.995072','2025-08-11 17:53:41.995072',NULL,NULL,NULL,NULL),(29,5,'Uma pequena empresa planeja comprar um caminhão novo, à vista, cujo preço de mercado equivale a R$ 250.000,00, mas ela não dispõe, no momento, de qualquer valor em caixa para realizar a transação. Caso a empresa consiga obter um retorno nominal de 5% a.a., com base no valor presente, qual o montante que ela deveria aplicar hoje para viabilizar a compra do caminhão, à vista, daqui a 4 anos, supondo que o preço do bem permaneça inalterado nesse período?','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','hard',3.80,0,0,42.00,NULL,NULL,1,'2025-08-11 17:53:42.609622','2025-08-11 17:53:42.609622',NULL,NULL,NULL,NULL),(30,5,'Uma empresa avalia antecipar o pagamento das duas últimas parcelas de um financiamento, realizado a uma taxa de juro de 5% ao mês, para abril de 2018. As parcelas, no valor de R$ 8.820,00 cada uma, têm data de vencimento para maio de 2018 e junho de 2018. Considerando-se o desconto racional composto, o valor de quitação total das duas parcelas, se o pagamento das duas for realizado em abril de 2018, é igual a','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','hard',3.90,0,0,38.00,NULL,NULL,1,'2025-08-11 17:53:43.303571','2025-08-11 17:53:43.303571',NULL,NULL,NULL,NULL),(31,6,'No contexto do federalismo fiscal brasileiro, um dos desafios centrais é o desequilíbrio horizontal entre os entes federativos. Qual das alternativas abaixo apresenta a solução mais compatível com os princípios constitucionais?','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','hard',4.00,0,0,35.00,NULL,NULL,1,'2025-08-11 17:53:43.938969','2025-08-11 17:53:43.938969',NULL,NULL,NULL,NULL),(32,6,'Regtechs e Suptechs têm se destacado como grandes tendências no sistema financeiro. Com a modernização do setor e o crescimento das fintechs, o mundo tem presenciado uma série de transformações regulatórias para acompanhar e fomentar essas inovações. Nesse contexto, analise as seguintes afirmações sobre Regtech e Suptech. I. Suptech é voltada para as autoridades reguladoras, permitindo monitorar em tempo real o mercado e as instituições financeiras. Com o uso de big data e análise preditiva, essas tecnologias ajudam a identificar riscos, prevenir crises e garantir a estabilidade financeira. II. O Suptech é voltado tanto para as autoridades reguladoras quanto para as empresas, com o objetivo de aprimorar a supervisão dos sistemas, aumentando a eficiência no monitoramento de transações e na detecção de fraudes. III. As soluções de Regtech se concentram exclusivamente na gestão de dados e riscos das empresas, sem abordar aspectos relacionados a compliance ou a geração de relatórios regulatórios. Está correto o que se afirma em','multiple_choice','Escola Nacional de Concursos',2024,'Bancário','medium',3.50,0,0,48.00,NULL,NULL,1,'2025-08-11 17:53:44.528545','2025-08-11 17:53:44.528545',NULL,NULL,NULL,NULL),(33,6,'É uma espécie de título da dívida pública do Brasil que objetiva levantar recursos, visando cobrir déficits orçamen